VALUES
  ('promotion-d0d1b9a2-moex-00093', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，下列交易事項之處理，何者正確？', '["購買材料時借記業務支出", "使用材料時貸記公庫撥入數", "繳回零用金時借記繳付公庫數", "收回以前年度支付之存出保證金時借記繳付公庫數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00094', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，經濟部對高雄市所屬作業基金之應付未付款項， 經濟部會計報告應以下列何科目列帳？', '["應付帳款", "應付其他政府款", "預收其他政府款", "應付其他基金款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00095', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '乙機關收到X2年度決算之審定通知書，審計部修正或剔除之事項如下：①一般事務費10萬元應', '["未取具合法原始憑證，剔除一般事務費9萬元", "預收所屬A基金分攤〇〇計 畫執行款項300萬元應予轉正", "剔除專案保留數100萬元。依中央政府普通公務單位會計制度 之一致規定，乙機關依審定結果所作之會計分錄，會影響資產負債淨額者有幾項？", "1項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00096', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '甲機關X3年3月，依行政院政策決定，在符合所屬A特別收入基金用途之前提下，由該基金執 行某政策至年底，預估所需經費4億元由該基金先行籌應，並已納編次年度預算撥還A基金。迄 至X3年12月31日，A基金實際支付3億4,500萬元。依中央政府普通公務單位會計制度之一 致規定，年度終了時，甲機關及A基金查明應收應付事項時，針對上述交易應做如何處理？', '["A基金認列應收其他政府款3億4,500萬元，甲機關認列應付其他基金款3億4,500萬元", "A基金認列應收其他政府款4億元，甲機關認列應付其他基金款4億元", "僅A基金需認列應收其他政府款3億4,500萬元，甲機關附註揭露承諾事項3億4,500萬元", "均不作分錄，但須分別於A基金及甲機關財務報告中附註揭露承諾事項3億4,500萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00097', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '甲機關X1會計年度終了時，將歲出預算所列技術更新業務等經費共2,000萬元保留轉入X2年度 繼續執行，並於X2年3月20日支付經費500萬元。依中央政府普通公務單位會計制度之一致規 定，其X2年3月20日應記載之會計分錄，下列何者正確？', '["借：資產負債淨額500萬元，貸：公庫撥入數500萬元；借：歲出保留數準備500萬元，貸： 歲出保留數500萬元", "借：業務支出500萬元，貸：公庫撥入數500萬元；借：歲出保留數準備500萬元，貸：歲出 保留數500萬元", "借：資產負債淨額500萬元，貸：應付帳款500萬元；借：歲出保留數500萬元，貸：歲出保 留數準備500萬元", "借：業務支出500萬元，貸：應付帳款500萬元；借：歲出保留數準備500萬元，貸：歲出保 留數500萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00098', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '乙機關X1年度單位預算案中，歲出預算數編列13億2,674萬元，送立法院審議後，經總統於X1 年2月16日公布乙機關歲出預算數13億1,266萬元（含第一預備金185萬元）。假設乙機關X1 年度未申請動支第一預備金，X1年9月間申請並奉准後如數動支第二預備金2億1,280萬元，執 行結果於年度終了時，依規定申請歲出預算保留123萬元。乙機關結帳時應結清歲出分配數及歲 出保留數各多少元？', '["15億2,546萬元、無列數（0元）", "15億2,361萬元、123萬元", "13億1,266萬元、無列數（0元）", "13億1,081萬元、123萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00099', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '中央政府國庫主管機關核定中央政府甲機關零用金額度70,000元。X8年11月1日甲機關出納管 理單位，為應緊急及零星支用，簽奉機關首長核准設置50,000元零用金，作為零星支用；X8年 11月30日甲機關由零用金支付國內出差旅費7,500元、運費8,000元；X8年12月1日撥還零用 金；X8年12月15日甲機關由零用金支付車輛及辦公器具養護費9,000元、國內出差旅費9,500 元、運費9,900元、短程車資9,990元、郵資8,500元，並依規定程序撥還；X8年12月31日甲 機關依規定，將該年度零用金餘額繳還國庫，依中央政府普通公務單位會計制度之一致規定，試 作零用金繳回之會計分錄？', '["借：公庫撥入數50,000元，貸：零用金50,000元", "借：公庫撥入數70,000元，貸：零用金70,000元", "借：公庫撥入數34,500元，貸：零用金34,500元", "借：公庫撥入數3,110元，貸：零用金3,110元 12140"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00100', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '丙機關於X3年1月預撥補助A財團法人500萬元，該法人依進度於X3年4月申請核銷150萬 元，但因有與補助目的不符之支出50萬元，丙機關要求A法人繳回，後續亦不再支用，其餘同 意核銷，丙機關於X3年5月1日存入一紙發票日為5月15日之支票，並立即存入機關專戶。依 中央政府普通公務單位會計制度之一致規定，下列何者非本交易之分錄？', '["借：預付款500萬元，貸：公庫撥入數500萬元", "借：應收票據50萬元，貸：預付款50萬元", "借：獎補助支出100萬元，貸：預付款100萬元", "借：繳付公庫數50萬元，貸：獎補助支出50萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00101', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '甲機關辦理查驗案件業務，每一個案件收取規費1萬元，以電子方式提出申請者得減收1,000元。 A廠商X3年12月1 日以電子方式向甲機關申請一個案件查驗，並繳納現金1萬元。甲機關於 X3年12月30日查驗完成後，認列規費收入1萬元並繳庫；A廠商於X3年12月31日向甲機關 申請退費1,000元。審計機關爰修正減列甲機關X3年收入實現數1,000元，另甲機關將已繳庫之 收入款領回存入機關專戶後，尚待循程序辦理退費事宜。依中央政府普通公務單位會計制度之一 致規定，有關審計機關修正減列收入實現數及甲機關將款項退還A廠商之會計分錄為何？', '["借：資產負債淨額1,000元，貸：預收款1,000元；借：預收款1,000元，貸：繳付公庫數1,000元", "借：資產負債淨額1,000元，貸：預收款1,000元；借：預收款1,000元，貸：各機關現金1,000元", "借：資產負債淨額1,000元，貸：預收款1,000元；借：預收款1,000元，貸：專戶存款1,000元", "借：資產負債淨額1,000元，貸：預收款1,000元；借：預收款1,000元，貸：公庫撥入數1,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00102', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定之繳付公庫數分析表，下列會使年終結帳前繳付公', '["預付當年度契約款", "以前年度撥款於本年度繳還數", "收 回以前年度撥款之存出保證金", "退還本年度收入數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
